```csharp
public class ProxyMiddleware
{
    private readonly RequestDelegate _next;
    private readonly string _targetUrl;

    public ProxyMiddleware(RequestDelegate next, string targetUrl)
    {
        _next = next;
        _targetUrl = targetUrl;
    }

    public async Task InvokeAsync(HttpContext context)
    {
        if (context.Request.Path.StartsWith("/proxy"))
        {
            var originalUrl = new Uri(context.Request.Scheme + "://" + context.Request.Host + context.Request.Path);
            var targetUri = new Uri(_targetUrl + context.Request.Path);

            context.Request.Scheme = targetUri.Scheme;
            context.Request.Host = targetUri.Host;
            context.Request.Path = targetUri.AbsolutePath;

            await _next(context);
        }
        else
        {
            await _next(context);
        }
    }
}
```

